import createReducer from '~/redux/store/createReducer'

/**
 * Types
 */
export interface TypesType {
  REQUEST: string;
  SUCESS: string;
  FAILED: string;
  CLEAR: string;
}

export const Types: TypesType = {
  REQUEST: 'example/request',
  SUCESS: 'example/sucess',
  FAILED: 'example/failed',
  CLEAR: 'example/clear',
}
/**
 * Initial State
 */
interface InitialState {
  isLoading: boolean
  isError: boolean
  data: string
}

export type State = InitialState

export const initialState: InitialState = {
  isLoading: false,
  isError: false,
  data: '',
}

/**
 * Reducers
 */
export const exampleReducer = createReducer(initialState, {
  [Types.REQUEST](state: State) {
    return {
      ...state,
      isLoading: true,
      isError: false,
    }
  },
  [Types.SUCESS](state: State, { data }: { data: string }) {
    return {
      ...state,
      data,
      isLoading: false,
      isError: false,
    }
  },
  [Types.FAILED](state: State) {
    return {
      ...state,
      isLoading: false,
      isError: true,
    }
  },
  [Types.CLEAR](state: State) {
    return {
      ...state,
      ...initialState,
    }
  },
})
/**
 * Actions
 */
export type CreatorsType = {
  requestExample: (data: { test1: string, test2: string }) => DataTransfer;
  success: (data: string) => DataTransfer;
  fail: () => DataTransfer;
  clear: () => DataTransfer;
}

export const Creators: CreatorsType = {
  requestExample: (data: { test1: string, test2: string }) => ({
    type: Types.REQUEST,
    data,
  }),
  success: (data: string) => ({
    type: Types.SUCESS,
    data,
  }),
  fail: () => ({
    type: Types.FAILED,
  }),
  clear: () => ({
    type: Types.CLEAR,
  }),
}
/**/
export default exampleReducer
